E = AUTO, MAX_PLANS_PER_QUERY = 200, WAIT_STATS_CAPTURE_MODE = ON)\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']","object_type":"Database"}},{"cell_type":"markdown","source":["# [dbo].[fn_CalcMoney_Transaction]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/UserDefinedFunction[@Name='fn_CalcMoney_Transaction' and @Schema='dbo']","object_type":"UserDefinedFunction"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["USE [QuanLyCamDo]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/UserDefinedFunction[@Name='fn_CalcMoney_Transaction' and @Schema='dbo']","object_type":"UserDefinedFunction"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  UserDefinedFunction [dbo].[fn_CalcMoney_Transaction]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- Function fn_CalcMoney_Transaction: Tính Dư nợ của Hợp đồng ngay tại thời điểm xảy ra 1 Log giao dịch\r\nCREATE FUNCTION [dbo].[fn_CalcMoney_Transaction] (@MaLog INT)\r\nRETURNS DECIMAL(18,2)\r\nAS\r\nBEGIN\r\n    DECLARE @MaHD INT, @NgayGiaoDich DATETIME;\r\n    SELECT @MaHD = MaHD, @NgayGiaoDich = NgayGiaoDich FROM LogGiaoDich WHERE MaLog = @MaLog;\r\n    \r\n    -- Gọi lại hàm tính tổng tiền tính đến ngày giao dịch đó\r\n    RETURN dbo.fn_CalcMoneyContract(@MaHD, @NgayGiaoDich);\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/UserDefinedFunction[@Name='fn_CalcMoney_Transaction' and @Schema='dbo']","object_type":"UserDefinedFunction"}},{"cell_type":"markdown","source":["# [dbo].[fn_CalcMoneyContract]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/UserDefinedFunction[@Name='fn_CalcMoneyContract' and @Schema='dbo']","object_type":"UserDefinedFunction"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  UserDefinedFunction [dbo].[fn_CalcMoneyContract]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE FUNCTION [dbo].[fn_CalcMoneyContract] (@MaHD INT, @TargetDate DATETIME)\r\nRETURNS DECIMAL(18,2)\r\nAS\r\nBEGIN\r\n    DECLARE @NgayVay DATETIME, @Deadline1 DATETIME, @TienGoc DECIMAL(18,2);\r\n    SELECT @NgayVay = CAST(NgayVay AS DATE), \r\n           @Deadline1 = CAST(Deadline1 AS DATE), \r\n           @TienGoc = TienGoc \r\n    FROM HopDong WHERE MaHD = @MaHD;\r\n\r\n    DECLARE @CurrDate DATE = @NgayVay;\r\n    DECLARE @Principal DECIMAL(18,2) = @TienGoc;\r\n    DECLARE @AccInterest DECIMAL(18,2) = 0;\r\n    DECLARE @DailyRate DECIMAL(18,6) = 0.005; -- 5000đ/1tr = 0.5%\r\n\r\n    WHILE @CurrDate < CAST(@TargetDate AS DATE)\r\n    BEGIN\r\n        SET @CurrDate = DATEADD(DAY, 1, @CurrDate);\r\n\r\n        -- Lấy số tiền khách trả trong ngày hôm nay\r\n        DECLARE @PaidToday DECIMAL(18,2) = ISNULL((\r\n            SELECT SUM(SoTienTra) FROM LogGiaoDich \r\n            WHERE MaHD = @MaHD AND CAST(NgayGiaoDich AS DATE) = @CurrDate\r\n        ), 0);\r\n\r\n        -- Trừ tiền trả (Ưu tiên trừ lãi trước, dư mới trừ gốc)\r\n        IF @PaidToday > 0\r\n        BEGIN\r\n            IF @PaidToday >= @AccInterest\r\n            BEGIN\r\n                SET @PaidToday = @PaidToday - @AccInterest;\r\n                SET @AccInterest = 0;\r\n                SET @Principal = @Principal - @PaidToday;\r\n            END\r\n            ELSE\r\n            BEGIN\r\n                SET @AccInterest = @AccInterest - @PaidToday;\r\n            END\r\n        END\r\n\r\n        -- Tính lãi cho ngày hôm nay\r\n        IF @CurrDate <= @Deadline1\r\n        BEGIN\r\n            -- Lãi đơn: Chỉ tính trên nợ gốc hiện tại\r\n            SET @AccInterest = @AccInterest + (@Principal * @DailyRate);\r\n        END\r\n        ELSE\r\n        BEGIN\r\n            -- Lãi kép: Tính trên (Gốc + Lãi đã tích lũy)\r\n            SET @AccInterest = @AccInterest + ((@Principal + @AccInterest) * @DailyRate);\r\n        END\r\n    END\r\n\r\n    -- Tổng nợ = Gốc còn lại + Lãi còn lại\r\n    RETURN CASE WHEN (@Principal + @AccInterest) < 0 THEN 0 ELSE (@Principal + @AccInterest) END;\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/UserDefinedFunction[@Name='fn_CalcMoneyContract' and @Schema='dbo']","object_type":"UserDefinedFunction"}},{"cell_type":"markdown","source":["# [dbo].[KhachHang]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='KhachHang' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[KhachHang]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[KhachHang](\r\n\t[MaKH] [int] IDENTITY(1,1) NOT NULL,\r\n\t[TenKH] [nvarchar](100) NOT NULL,\r\n\t[SDT] [varchar](15) NOT NULL,\r\n\t[CCCD] [varchar](20) NOT NULL,\r\n\t[DiaChi] [nvarchar](255) NULL,\r\n\t[NgayTao] [datetime] NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[MaKH] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY],\r\nUNIQUE NONCLUSTERED \r\n(\r\n\t[CCCD] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY],\r\nUNIQUE NONCLUSTERED \r\n(\r\n\t[SDT] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='KhachHang' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[HopDong]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[HopDong]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[HopDong](\r\n\t[MaHD] [int] IDENTITY(1,1) NOT NULL,\r\n\t[MaKH] [int] NOT NULL,\r\n\t[TienGoc] [decimal](18, 2) NOT NULL,\r\n\t[NgayVay] [datetime] NOT NULL,\r\n\t[Deadline1] [datetime] NOT NULL,\r\n\t[Deadline2] [datetime] NOT NULL,\r\n\t[TrangThai] [nvarchar](50) NULL,\r\n\t[GhiChu] [nvarchar](max) NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[MaHD] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[vw_BaoCaoNoXau]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/View[@Name='vw_BaoCaoNoXau' and @Schema='dbo']","object_type":"View"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  View [dbo].[vw_BaoCaoNoXau]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE VIEW [dbo].[vw_BaoCaoNoXau] AS\r\nSELECT \r\n    kh.TenKH,\r\n    kh.SDT,\r\n    hd.MaHD,\r\n    hd.TienGoc,\r\n    DATEDIFF(DAY, hd.Deadline1, GETDATE()) AS SoNgayQuaHan,\r\n    dbo.fn_CalcMoneyContract(hd.MaHD, GETDATE()) AS TongNoHienTai,\r\n    dbo.fn_CalcMoneyContract(hd.MaHD, DATEADD(MONTH, 1, GETDATE())) AS TongNoSau1ThangNua\r\nFROM HopDong hd\r\nJOIN KhachHang kh ON hd.MaKH = kh.MaKH\r\nWHERE hd.TrangThai NOT IN (N'Đã thanh toán', N'Đã thanh lý')\r\n  AND GETDATE() > hd.Deadline1;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/View[@Name='vw_BaoCaoNoXau' and @Schema='dbo']","object_type":"View"}},{"cell_type":"markdown","source":["# [dbo].[LogGiaoDich]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='LogGiaoDich' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[LogGiaoDich]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[LogGiaoDich](\r\n\t[MaLog] [int] IDENTITY(1,1) NOT NULL,\r\n\t[MaHD] [int] NOT NULL,\r\n\t[NgayGiaoDich] [datetime] NULL,\r\n\t[SoTienTra] [decimal](18, 2) NOT NULL,\r\n\t[LoaiGiaoDich] [nvarchar](50) NULL,\r\n\t[GhiChu] [nvarchar](255) NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[MaLog] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='LogGiaoDich' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [dbo].[TaiSan]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']","object_type":"Table"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  Table [dbo].[TaiSan]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE TABLE [dbo].[TaiSan](\r\n\t[MaTS] [int] IDENTITY(1,1) NOT NULL,\r\n\t[MaHD] [int] NOT NULL,\r\n\t[TenTS] [nvarchar](255) NOT NULL,\r\n\t[GiaTriDinhGia] [decimal](18, 2) NOT NULL,\r\n\t[TrangThai] [nvarchar](50) NULL,\r\nPRIMARY KEY CLUSTERED \r\n(\r\n\t[MaTS] ASC\r\n)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]\r\n) ON [PRIMARY]\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']","object_type":"Table"}},{"cell_type":"markdown","source":["# [DF__HopDong__NgayVay__3C69FB99]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/Column[@Name='NgayVay']/Default[@Name='DF__HopDong__NgayVay__3C69FB99']","object_type":"Default"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[HopDong] ADD  DEFAULT (getdate()) FOR [NgayVay]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/Column[@Name='NgayVay']/Default[@Name='DF__HopDong__NgayVay__3C69FB99']","object_type":"Default"}},{"cell_type":"markdown","source":["# [DF__HopDong__TrangTh__3D5E1FD2]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/Column[@Name='TrangThai']/Default[@Name='DF__HopDong__TrangTh__3D5E1FD2']","object_type":"Default"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[HopDong] ADD  DEFAULT (N'Đang vay') FOR [TrangThai]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/Column[@Name='TrangThai']/Default[@Name='DF__HopDong__TrangTh__3D5E1FD2']","object_type":"Default"}},{"cell_type":"markdown","source":["# [DF__K