iaoDi__LoaiG__45F365D3']","object_type":"Default"}},{"cell_type":"markdown","source":["# [DF__TaiSan__TrangTha__412EB0B6]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']/Column[@Name='TrangThai']/Default[@Name='DF__TaiSan__TrangTha__412EB0B6']","object_type":"Default"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[TaiSan] ADD  DEFAULT (N'Đang cầm cố') FOR [TrangThai]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']/Column[@Name='TrangThai']/Default[@Name='DF__TaiSan__TrangTha__412EB0B6']","object_type":"Default"}},{"cell_type":"markdown","source":["# [FK_HopDong_KhachHang]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/ForeignKey[@Name='FK_HopDong_KhachHang']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[HopDong]  WITH CHECK ADD  CONSTRAINT [FK_HopDong_KhachHang] FOREIGN KEY([MaKH])\r\nREFERENCES [dbo].[KhachHang] ([MaKH])\r\n","GO\r\n","ALTER TABLE [dbo].[HopDong] CHECK CONSTRAINT [FK_HopDong_KhachHang]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='HopDong' and @Schema='dbo']/ForeignKey[@Name='FK_HopDong_KhachHang']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK_Log_HopDong]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='LogGiaoDich' and @Schema='dbo']/ForeignKey[@Name='FK_Log_HopDong']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[LogGiaoDich]  WITH CHECK ADD  CONSTRAINT [FK_Log_HopDong] FOREIGN KEY([MaHD])\r\nREFERENCES [dbo].[HopDong] ([MaHD])\r\n","GO\r\n","ALTER TABLE [dbo].[LogGiaoDich] CHECK CONSTRAINT [FK_Log_HopDong]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='LogGiaoDich' and @Schema='dbo']/ForeignKey[@Name='FK_Log_HopDong']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK_TaiSan_HopDong]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']/ForeignKey[@Name='FK_TaiSan_HopDong']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[TaiSan]  WITH CHECK ADD  CONSTRAINT [FK_TaiSan_HopDong] FOREIGN KEY([MaHD])\r\nREFERENCES [dbo].[HopDong] ([MaHD])\r\n","GO\r\n","ALTER TABLE [dbo].[TaiSan] CHECK CONSTRAINT [FK_TaiSan_HopDong]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/Table[@Name='TaiSan' and @Schema='dbo']/ForeignKey[@Name='FK_TaiSan_HopDong']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [dbo].[sp_Job_DailyCheckStatus]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_Job_DailyCheckStatus' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Job_DailyCheckStatus]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- SP dành cho SQL Agent Job (Chạy mỗi đêm để tự động hóa Trigger 1 & 2 theo thời gian)\r\nCREATE PROCEDURE [dbo].[sp_Job_DailyCheckStatus]\r\nAS\r\nBEGIN\r\n    -- Trigger 1 Logic: Đang vay -> Quá hạn nếu lố Deadline 1\r\n    UPDATE HopDong\r\n    SET TrangThai = N'Quá hạn'\r\n    WHERE TrangThai IN (N'Đang vay', N'Đang trả góp') \r\n      AND GETDATE() > Deadline1;\r\n\r\n    -- Trigger 2 Logic: Tài sản -> Sẵn sàng thanh lý nếu Hợp đồng Quá hạn và lố Deadline 2\r\n    UPDATE TaiSan\r\n    SET TrangThai = N'Sẵn sàng thanh lý'\r\n    FROM TaiSan ts\r\n    JOIN HopDong hd ON ts.MaHD = hd.MaHD\r\n    WHERE hd.TrangThai = N'Quá hạn' \r\n      AND GETDATE() > hd.Deadline2\r\n      AND ts.TrangThai = N'Đang cầm cố';\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_Job_DailyCheckStatus' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_TaoHopDong]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_TaoHopDong' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_TaoHopDong]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_TaoHopDong]\r\n    @MaKH INT,\r\n    @TienGoc DECIMAL(18,2),\r\n    @ThoiGianVayNgay INT,\r\n    @JsonTaiSan NVARCHAR(MAX) -- Format: '[{\"TenTS\":\"iPhone 14\",\"GiaTri\":15000000}, ...]'\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n    BEGIN TRY\r\n        BEGIN TRAN;\r\n        \r\n        DECLARE @NgayVay DATETIME = GETDATE();\r\n        DECLARE @Deadline1 DATETIME = DATEADD(DAY, @ThoiGianVayNgay, @NgayVay);\r\n        DECLARE @Deadline2 DATETIME = DATEADD(DAY, @ThoiGianVayNgay + 30, @NgayVay); -- Giả sử DL2 sau DL1 30 ngày\r\n        DECLARE @MaHD INT;\r\n\r\n        -- Insert Hợp đồng\r\n        INSERT INTO HopDong (MaKH, TienGoc, NgayVay, Deadline1, Deadline2, TrangThai)\r\n        VALUES (@MaKH, @TienGoc, @NgayVay, @Deadline1, @Deadline2, N'Đang vay');\r\n        \r\n        SET @MaHD = SCOPE_IDENTITY();\r\n\r\n        -- Insert Tài sản từ JSON\r\n        INSERT INTO TaiSan (MaHD, TenTS, GiaTriDinhGia, TrangThai)\r\n        SELECT @MaHD, \r\n               JSON_VALUE(value, '$.TenTS'), \r\n               CAST(JSON_VALUE(value, '$.GiaTri') AS DECIMAL(18,2)), \r\n               N'Đang cầm cố'\r\n        FROM OPENJSON(@JsonTaiSan);\r\n\r\n        COMMIT TRAN;\r\n        SELECT @MaHD AS MaHD_MoiTao, N'Tạo hợp đồng thành công' AS Message;\r\n    END TRY\r\n    BEGIN CATCH\r\n        ROLLBACK TRAN;\r\n        THROW;\r\n    END CATCH\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_TaoHopDong' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_XuLyTraNo]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_XuLyTraNo' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_XuLyTraNo]    Script Date: 12/05/2026 22:18 CH ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_XuLyTraNo]\r\n    @MaHD INT,\r\n    @SoTienTra DECIMAL(18,2)\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n    \r\n    -- 1. Kiểm tra tài sản đã bị bán thanh lý chưa\r\n    IF EXISTS (SELECT 1 FROM TaiSan WHERE MaHD = @MaHD AND TrangThai = N'Đã bán thanh lý')\r\n    BEGIN\r\n        PRINT N'LỖI: Tài sản đã bị bán thanh lý. Không thu tiền, không trả đồ.';\r\n        RETURN;\r\n    END\r\n\r\n    -- 2. Tính dư nợ hiện tại\r\n    DECLARE @DuNoHienTai DECIMAL(18,2) = dbo.fn_CalcMoneyContract(@MaHD, GETDATE());\r\n    \r\n    -- 3. Ghi Log Giao Dịch\r\n    INSERT INTO LogGiaoDich (MaHD, SoTienTra, LoaiGiaoDich)\r\n    VALUES (@MaHD, @SoTienTra, CASE WHEN @SoTienTra >= @DuNoHienTai THEN N'Tất toán' ELSE N'Trả góp' END);\r\n\r\n    -- 4. Cập nhật trạng thái Hợp đồng\r\n    DECLARE @DuNoSauKhiTra DECIMAL(18,2) = @DuNoHienTai - @SoTienTra;\r\n    \r\n    IF @DuNoSauKhiTra <= 0\r\n    BEGIN\r\n        UPDATE HopDong SET TrangThai = N'Đã thanh toán' WHERE MaHD = @MaHD;\r\n        UPDATE TaiSan SET TrangThai = N'Đã trả khách' WHERE MaHD = @MaHD AND TrangThai = N'Đang cầm cố';\r\n        PRINT N'Khách đã thanh toán đủ. Hợp đồng tất toán. Trả toàn bộ tài sản.';\r\n    END\r\n    ELSE\r\n    BEGIN\r\n        UPDATE HopDong SET TrangThai = N'Đang trả góp' WHERE MaHD = @MaHD;\r\n        PRINT N'Đã ghi nhận trả góp. Dư nợ còn lại: ' + CAST(@DuNoSauKhiTra AS NVARCHAR(50));\r\n\r\n        -- 5. Gợi ý tài sản có thể trả lại cho khách\r\n        -- Điều kiện: Tổng giá trị TS còn lại (Đang cầm cố) trừ đi TS định trả >= Dư nợ còn lại\r\n        DECLARE @TongGiaTriDangCamCo DECIMAL(18,2);\r\n        SELECT @TongGiaTriDangCamCo = ISNULL(SUM(GiaTriDinhGia), 0) \r\n        FROM TaiSan WHERE MaHD = @MaHD AND TrangThai = N'Đang cầm cố';\r\n\r\n        SELECT MaTS, TenTS, GiaTriDinhGia, \r\n               N'Có thể trả' AS GoiY\r\n        FROM TaiSan \r\n        WHERE MaHD = @MaHD AND TrangThai = N'Đang cầm cố'\r\n          AND (@TongGiaTriDangCamCo - GiaTriDinhGia) >= @DuNoSauKhiTra;\r\n    END\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']/StoredProcedure[@Name='sp_XuLyTraNo' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [QuanLyCamDo]"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["USE [master]\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']","object_type":"Database"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER DATABASE [QuanLyCamDo] SET  READ_WRITE \r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='Hung28052005\\SQLEXPRESS']/Database[@Name='QuanLyCamDo']","object_type":"Database"}}]}